func bisectLeft(arr []int64, target int64) int {
	left, right := 0, len(arr)
	for left < right {
		mid := (left + right) / 2
		if arr[mid] < target {
			left = mid + 1
		} else {
			right = mid
		}
	}
	return left
}

func bisectRight(arr []int64, target int64) int {
	left, right := 0, len(arr)
	for left < right {
		mid := (left + right) / 2
		if arr[mid] <= target {
			left = mid + 1
		} else {
			right = mid
		}
	}
	return left
}

func solve(nums []int64, queries [][]int64) []int64 {
	posMap := make(map[int64][]int64)
	for i, num := range nums {
		if _, exists := posMap[num]; !exists {
			posMap[num] = make([]int64, 0)
		}
		posMap[num] = append(posMap[num], int64(i))
	}

	result := make([]int64, len(queries))
	for i, query := range queries {
		l, r, threshold := query[0], query[1], query[2]
		maxFreq := -1
